fun <T> withCorrelationId(action: () -> T): T {
    val correlationId = MDC.get(CORRELATION_ID_MDC_NAME)
    return if (correlationId.isNullOrBlank()) {
        runWithMDC(CORRELATION_ID_MDC_NAME, hentKorrelasjonFraKjenteMDCKeys()) {
            action()
        }
    } else {
        action()
    }
}

